document.addEventListener("DOMContentLoaded", function () {
  // Initialize Theater.js
  var theater = TheaterJS();

  // Define the text animation
  theater
    .addActor("name", { speed: 0.7 }) // Optional: Adjust typing speed
    .addScene("name", [
      { text: "Junaid Ahmed", delay: 500 }, // Start with a delay if needed
      theater.next(),
    ])
    .addActor("description", { speed: 0.7 })
    .addScene("description", [
      { text: "18, Sophomore CS student", delay: 500 },
    ]);

  // Start the animation
  theater.play();
});
